select matricola
from studenti
where nome='Mario' and cognome='Rossi' and iscrizione=2009;

select matricola
from studenti join corsidilaurea on corsodilaurea=id
where corsidilaurea.denominazione='Informatica' and laurea < '11/01/2011';

select distinct cognome
from studenti
where residenza <> 'Genova';

select distinct residenza
from studenti
order by residenza;

select matricola, cognome, nome
from studenti
where iscrizione < 2010 and relatore is null;

select id
from professori
where nome like '%te%'and stipendio between 12500.00 and 16000.00;

select distinct studente
from esami
where data >= '02/02/2009';

select cognome, nome, denominazione, corsi.id
from professori join corsi on professori.id=professore
order by corsi.id desc;

select nome fname, cognome lname, extract(year from age(datanascita)) age
from studenti
order by age desc;

select denominazione, count(*) as "nIscritti"
from studenti join corsidilaurea on corsodilaurea=id
group by id, denominazione;
